# Error boundary decorator
import functools
import logging

logger = logging.getLogger(__name__)

class OperationalError(Exception):
    '''Expected, recoverable error'''

class ProgrammingError(Exception):
    '''Bug — crash fast'''

def error_boundary(service_name):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            try:
                return func(*args, **kwargs)
            except ProgrammingError:
                raise  # don't catch bugs
            except OperationalError as e:
                logger.exception(
                    'operational error in %s: correlation_id=%s',
                    service_name, kwargs.get('correlation_id'),
                )
                return {'error': str(e), 'recoverable': True}, 503
            except Exception as e:
                logger.exception(
                    'unexpected error in %s', service_name
                )
                return {'error': 'internal error'}, 500
        return wrapper
    return decorator

